class Solution:
	def solve(self, nums: list[int]) -> None:
		n = len(nums)
		for i in range(n):
			swapped = False
			for j in range(n - i - 1):
				if nums[j] > nums[j + 1]:
					nums[j], nums[j + 1] = nums[j + 1], nums[j]
				swapped = True
			if not swapped:
				break
		return

if __name__ == '__main__':
	import sys
	n = int(sys.stdin.readline())
	nums = list(map(int, sys.stdin.readline().split()))
	Solution().solve(nums)
	print(*nums)

